#include <queue>
#include <vector>
#include <iostream>
#include <algorithm>
#include <functional>
using namespace std;

const vector<int> dx = { -1, 0, 1, 0 };
const vector<int> dy = { 0, 1, 0, -1 };

class action {
public:
	int tp, a, b;
	action() : tp(-1), a(-1), b(-1) {};
	action(int tp_, int a_, int b_) : tp(tp_), a(a_), b(b_) {};
};

class player {
public:
	int x, y, score, wallcnt;
	player() : x(-1), y(-1), score(0), wallcnt(0) {};
	player(int x_, int y_, int score_, int wallcnt_) : x(x_), y(y_), score(score_), wallcnt(wallcnt_) {};
};

class board {
public:
	static const int N = 9;
	vector<vector<bool> > apple;
	vector<vector<bool> > wallx, wally;
	player self, enemy;
	board() {
		apple = vector<vector<bool> >(N, vector<bool>(N, false));
		wallx = vector<vector<bool> >(N, vector<bool>(N - 1, false));
		wally = vector<vector<bool> >(N - 1, vector<bool>(N, false));
		self = player(8, 4, 0, 0);
		enemy = player(0, 4, 0, 0);
	};
	bool canmove(int x, int y, int dir) const {
		if (dir == 0) {
			return (x >= 1 && !wally[x - 1][y]);
		}
		if (dir == 1) {
			return (y <= N - 2 && !wallx[x][y]);
		}
		if (dir == 2) {
			return (x <= N - 2 && !wally[x][y]);
		}
		if (dir == 3) {
			return (y >= 1 && !wallx[x][y - 1]);
		}
		return false;
	}
	bool connected() const {
		vector<vector<bool> > vis(N, vector<bool>(N, false));
		function<void(int, int)> dfs = [&](int x, int y) {
			vis[x][y] = true;
			for (int i = 0; i < 4; i++) {
				if (canmove(x, y, i) && !vis[x + dx[i]][y + dy[i]]) {
					dfs(x + dx[i], y + dy[i]);
				}
			}
		};
		dfs(0, 0);
		for (int i = 0; i < N; i++) {
			for (int j = 0; j < N; j++) {
				if (!vis[i][j]) {
					return false;
				}
			}
		}
		return true;
	}
	vector<vector<int> > get_distance_list(int sx, int sy) const {
		vector<vector<int> > dist(N, vector<int>(N, -1));
		dist[sx][sy] = 0;
		queue<pair<int, int> > que;
		que.push(make_pair(sx, sy));
		while (!que.empty()) {
			int x = que.front().first;
			int y = que.front().second;
			que.pop();
			for (int i = 0; i < 4; i++) {
				if (canmove(x, y, i) && dist[x + dx[i]][y + dy[i]] == -1) {
					dist[x + dx[i]][y + dy[i]] = dist[x][y] + 1;
					que.push(make_pair(x + dx[i], y + dy[i]));
				}
			}
		}
		return dist;
	}
	vector<action> listup_action() const {
		board fb(*this);
		vector<action> res;
		for (int i = 0; i < 4; i++) {
			if (canmove(self.x, self.y, i)) {
				res.push_back(action(0, i, -1));
			}
		}
		if (self.wallcnt < 10) {
			for (int i = 0; i <= N - 2; i++) {
				for (int j = 0; j <= N - 2; j++) {
					if (wally[i][j] == false && wally[i][j + 1] == false) {
						fb.wally[i][j] = true;
						fb.wally[i][j + 1] = true;
						if (fb.connected()) {
							res.push_back(action(1, i, j));
						}
						fb.wally[i][j] = false;
						fb.wally[i][j + 1] = false;
					}
					if (wallx[i][j] == false && wallx[i + 1][j] == false) {
						fb.wallx[i][j] = true;
						fb.wallx[i + 1][j] = true;
						if (fb.connected()) {
							res.push_back(action(2, i, j));
						}
						fb.wallx[i][j] = false;
						fb.wallx[i + 1][j] = false;
					}
				}
			}
		}
		return res;
	}
	board apply_action(const action& m) const {
		board nb(*this);
		if (m.tp == 0) {
			nb.self.x += dx[m.a];
			nb.self.y += dy[m.a];
			if (nb.apple[nb.self.x][nb.self.y] == true) {
				nb.apple[nb.self.x][nb.self.y] = false;
				nb.self.score += 1;
			}
		}
		if (m.tp == 1) {
			nb.wally[m.a][m.b] = true;
			nb.wally[m.a][m.b + 1] = true;
			nb.self.wallcnt += 1;
		}
		if (m.tp == 2) {
			nb.wallx[m.a][m.b] = true;
			nb.wallx[m.a + 1][m.b] = true;
			nb.self.wallcnt += 1;
		}
		swap(nb.self, nb.enemy);
		return nb;
	}
	double eval() const {
		vector<vector<int> > d1 = get_distance_list(self.x, self.y);
		vector<vector<int> > d2 = get_distance_list(enemy.x, enemy.y);
		double answer = self.score - enemy.score;
		for (int i = 0; i < N; i++) {
			for (int j = 0; j < N; j++) {
				if (apple[i][j]) {
					answer += double(d2[i][j] - d1[i][j]) / (d2[i][j] + d1[i][j]);
				}
			}
		}
		return answer;
	}
};

action best_action(const board& B) {
	vector<action> action_list = B.listup_action();
	double best_eval = -1.0e+99;
	action best;
	for (action m : action_list) {
		board nb = B.apply_action(m);
		double eval = -nb.eval();
		// cerr << m.tp << ' ' << m.a << ' ' << m.b << ' ' << eval << endl;
		if (best_eval < eval) {
			best_eval = eval;
			best = m;
		}
	}
	return best;
}

int main() {
	string turnstr;
	cin >> turnstr;
	board B;
	for (int i = 0; i < 9; i++) {
		string str;
		cin >> str;
		for (int j = 0; j < 9; j++) {
			B.apple[i][j] = (str[j] == '#' ? true : false);
		}
	}
	int turn = (turnstr == "First" ? 0 : 1);
	while (true) {
		if (turn == 0) {
			// self's turn
			action best = best_action(B);
			B = B.apply_action(best);
			if (best.tp == 0) {
				cout << best.tp << ' ' << best.a << endl;
			}
			if (best.tp == 1 || best.tp == 2) {
				cout << best.tp << ' ' << best.a << ' ' << best.b << endl;
			}
		}
		if (turn == 1) {
			// enemy's turn
			action z;
			cin >> z.tp;
			if (z.tp == 0) {
				cin >> z.a;
			}
			if (z.tp == 1 || z.tp == 2) {
				cin >> z.a >> z.b;
			}
			if (z.tp == 3) {
				break;
			}
			B = B.apply_action(z);
		}
		turn ^= 1;
	}
	return 0;
}
